import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Play, Trash2, Music, ArrowLeft } from 'lucide-react';

const PlaylistDetail = () => {
  const { id } = useParams(); // Lấy ID playlist từ URL
  const navigate = useNavigate();
  const [playlist, setPlaylist] = useState(null);
  const [loading, setLoading] = useState(true);
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchPlaylist();
  }, [id]);

  const fetchPlaylist = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/playlists/${id}`);
      setPlaylist(res.data);
    } catch (err) {
      console.error("Lỗi tải playlist:", err);
    } finally {
      setLoading(false);
    }
  };

  // Xóa bài hát khỏi playlist (không xóa khỏi hệ thống)
  const handleRemoveSong = async (songId) => {
    if (!window.confirm("Bạn muốn bỏ bài hát này khỏi danh sách phát?")) return;
    try {
      await axios.put(`http://localhost:5000/api/playlists/${id}/remove`, { songId });
      // Cập nhật lại giao diện sau khi xóa thành công
      setPlaylist({
        ...playlist,
        songs: playlist.songs.filter(s => s._id !== songId)
      });
    } catch (err) {
      alert("Không thể xóa bài hát khỏi playlist");
    }
  };

  if (loading) return <div style={centerStyle}>Đang tải danh sách bài hát...</div>;
  if (!playlist) return <div style={centerStyle}>Không tìm thấy playlist này.</div>;

  return (
    <div style={containerStyle}>
      <button onClick={() => navigate(-1)} style={backBtnStyle}>
        <ArrowLeft size={20} /> Quay lại
      </button>

      <div style={headerStyle}>
        <div style={playlistImgStyle}>
           <Music size={60} color="#fff" />
        </div>
        <div>
          <h4 style={{ margin: 0, textTransform: 'uppercase', fontSize: '12px' }}>Playlist</h4>
          <h1 style={{ fontSize: '48px', margin: '10px 0' }}>{playlist.title}</h1>
          <p style={{ color: '#888' }}>
            Tạo bởi <strong>{playlist.owner?.username || 'Người dùng P2Tunes'}</strong> • {playlist.songs?.length} bài hát
          </p>
        </div>
      </div>

      <div style={listContainerStyle}>
        <div style={listHeaderStyle}>
          <div style={{ width: '40px' }}>#</div>
          <div style={{ flex: 1 }}>Tiêu đề</div>
          <div style={{ width: '150px' }}>Nghệ sĩ</div>
          <div style={{ width: '100px', textAlign: 'right' }}>Hành động</div>
        </div>

        {playlist.songs.map((song, index) => (
          <div key={song._id} style={songRowStyle}>
            <div style={{ width: '40px', color: '#888' }}>{index + 1}</div>
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: '15px' }}>
              <img src={`http://localhost:5000${song.imageUrl}`} alt="" style={smallImgStyle} />
              <span style={{ fontWeight: '500' }}>{song.title}</span>
            </div>
            <div style={{ width: '150px', color: '#666' }}>{song.artist}</div>
            <div style={{ width: '100px', textAlign: 'right', display: 'flex', justifyContent: 'flex-end', gap: '15px' }}>
              <Play size={18} color="#1db954" cursor="pointer" onClick={() => navigate('/')} />
              
              {/* Chỉ hiện nút xóa nếu mình là chủ sở hữu playlist */}
              {(loggedInUser?._id === playlist.owner?._id || loggedInUser?.id === playlist.owner?._id) && (
                <Trash2 
                  size={18} 
                  color="#ff4d4d" 
                  cursor="pointer" 
                  onClick={() => handleRemoveSong(song._id)} 
                />
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- STYLES ---
const containerStyle = { padding: '40px', maxWidth: '1100px', margin: '0 auto' };
const centerStyle = { textAlign: 'center', padding: '100px' };
const backBtnStyle = { display: 'flex', alignItems: 'center', gap: '8px', background: 'none', border: 'none', cursor: 'pointer', marginBottom: '20px', color: '#666' };
const headerStyle = { display: 'flex', gap: '30px', alignItems: 'flex-end', marginBottom: '40px' };
const playlistImgStyle = { width: '200px', height: '200px', background: 'linear-gradient(45deg, #282828, #121212)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 8px 24px rgba(0,0,0,0.3)' };
const listContainerStyle = { marginTop: '20px' };
const listHeaderStyle = { display: 'flex', padding: '10px 20px', borderBottom: '1px solid #eee', color: '#888', fontSize: '13px', textTransform: 'uppercase' };
const songRowStyle = { display: 'flex', alignItems: 'center', padding: '12px 20px', borderRadius: '8px', transition: '0.2s', borderBottom: '1px solid #fafafa' };
const smallImgStyle = { width: '40px', height: '40px', borderRadius: '4px', objectFit: 'cover' };

export default PlaylistDetail;
